mapper.select:
SELECT ce.id, ce.character_id AS characterId, ce.chapter_id AS chapterId, ce.event_description AS eventDescription, bc.sort_order AS sortOrder, bc.title AS chapterTitle FROM character_event ce JOIN book_chapter bc ON ce.chapter_id = bc.id WHERE ce.character_id = #{characterId}
AND bc.sort_order <= #{maxSortOrder}
ORDER BY bc.sort_order ASC
